import pytest

# Assuming this function is imported from your module.
# Included here for self-contained execution.
def group_by(items: list, key_fn) -> dict:
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result


class TestGroupBy:
    # ==================== HAPPY PATH ====================
    def test_groups_by_numeric_key(self):
        items = [1, 2, 3, 4, 5, 6]
        result = group_by(items, lambda x: x % 2)
        assert result == {1: [1, 3, 5], 0: [2, 4, 6]}

    def test_groups_by_string_key(self):
        items = ["apple", "banana", "apricot", "blueberry"]
        result = group_by(items, lambda x: x[0])
        assert result == {"a": ["apple", "apricot"], "b": ["banana", "blueberry"]}

    def test_preserves_insertion_order(self):
        """Python 3.7+ dicts preserve insertion order. Keys should appear in 
        first-occurrence order, and value lists should preserve original order."""
        items = [3, 1, 2, 3, 1]
        result = group_by(items, lambda x: x)
        assert list(result.keys()) == [3, 1, 2]
        assert result[3] == [3, 3]
        assert result[1] == [1, 1]
        assert result[2] == [2]

    # ==================== EDGE CASES ====================
    def test_empty_list(self):
        assert group_by([], lambda x: x) == {}

    def test_single_item(self):
        assert group_by([42], lambda x: x) == {42: [42]}

    def test_all_items_map_to_same_key(self):
        items = ["a", "b", "c"]
        result = group_by(items, lambda x: "same")
        assert result == {"same": ["a", "b", "c"]}

    def test_all_items_map_to_unique_keys(self):
        items = [1, 2, 3]
        result = group_by(items, lambda x: x)
        assert result == {1: [1], 2: [2], 3: [3]}

    def test_key_function_returns_none(self):
        items = [1, 2, 3]
        result = group_by(items, lambda x: None)
        assert result == {None: [1, 2, 3]}

    def test_key_function_returns_tuple(self):
        items = [(1, 2), (1, 3), (2, 2)]
        result = group_by(items, lambda x: x[0])
        assert result == {1: [(1, 2), (1, 3)], 2: [(2, 2)]}

    def test_does_not_mutate_original_list(self):
        items = [1, 2, 3]
        original = items.copy()
        group_by(items, lambda x: x % 2)
        assert items == original

    # ==================== ERROR CASES ====================
    def test_raises_when_key_fn_not_callable(self):
        with pytest.raises(TypeError, match="object is not callable"):
            group_by([1, 2], "not_callable")

    def test_raises_when_key_fn_raises_exception(self):
        def bad_fn(x):
            if x == 2:
                raise ValueError("boom")
            return x

        with pytest.raises(ValueError, match="boom"):
            group_by([1, 2, 3], bad_fn)

    def test_raises_when_items_not_iterable(self):
        with pytest.raises(TypeError, match="object is not iterable"):
            group_by(123, lambda x: x)

    def test_raises_when_key_returns_unhashable_type(self):
        """Dictionary keys must be hashable. Returning a list should fail."""
        with pytest.raises(TypeError, match="unhashable type"):
            group_by([1, 2], lambda x: [x])
